  "for the current installer.": { ko: "현재 설치 프로그램을 확인하세요.", en: "for the current installer.", ja: "現行インストーラーを確認してください。" },
  "How does licensing work?": { ko: "라이선스는 어떻게 작동하나요?", en: "How does licensing work?", ja: "ライセンスはどのように機能しますか?" },
